// Thin wrapper around the vendored wasm-bindgen build of engine/src/lib.rs
// (regenerated by engine/build-wasm.sh into site/vendor/engine, gitignored).
// Isolating the wasm import here means the rest of the app only depends on
// this module's plain-JS shape, not on wasm-bindgen's generated API.
import init, { simulate_market_order_js } from "../vendor/engine/order_flow_engine.js";

let ready = null;

/**
 * Loads and initializes the wasm matching engine. Safe to call multiple
 * times; the underlying wasm module is only instantiated once.
 * @returns {Promise<{simulateMarketOrder: (levels: Array<{price: number, size: number}>, sideIsBuy: boolean, orderSize: number) => object}>}
 */
export function loadEngine() {
  if (!ready) {
    ready = init().then(() => ({
      simulateMarketOrder(levels, sideIsBuy, orderSize) {
        return simulate_market_order_js(JSON.stringify(levels), sideIsBuy, orderSize);
      },
    }));
  }
  return ready;
}
